private readonly onArrowKeyDown = (event: KeyboardEvent): void => {
        if (event.key === 'ArrowUp') {
            this.applyScroll(this.cfg.SCROLL_STEP);
        } else if (event.key === 'ArrowDown') {
            this.applyScroll(-this.cfg.SCROLL_STEP);
        }
    };

